import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.*;
import java.util.*;

public class SecureXSSExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        String encodedUserInput = encodeForHTML(userInput); // Encode user input

        System.out.println("Hello, " + encodedUserInput + "!"); // Safe output

        scanner.close();
    }

    private static String encodeForHTML(String input) {
        try {
            return ESAPI.encoder().encodeForHTML(input);
        } catch (EncodingException e) {
            System.err.println("Encoding error: " + e.getMessage());
            return ""; // Handle encoding error gracefully
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
